__kernel void kernel_gpu(
	__global params_common* common,
	__global int* endoRow, __global int* endoCol, __global int* tEndoRowLoc, __global int* tEndoColLoc,
	__global int* epiRow, __global int* epiCol, __global int* tEpiRowLoc, __global int* tEpiColLoc,
	__global fp* d_endoT, __global fp* d_epiT,
	__global fp* d_frame, int frame_no,
	__global fp* d_in2, __global fp* d_in2_sqr,
	__global fp* d_in_mod, __global fp* d_in_sqr,
	__global fp* d_conv,
	__global fp* d_in2_pad,
	__global fp* d_in2_sub,
	__global fp* d_in2_sub2_sqr,
	__global fp* d_tMask,
	__global fp* d_mask_conv
) {
	int point_no = get_global_id(0);

	if (point_no >= common->allPoints) return;

	int is_endo = (point_no < common->endoPoints);

	__global int* d_Row = is_endo ? endoRow : epiRow;
	__global int* d_Col = is_endo ? endoCol : epiCol;
	__global int* d_tRowLoc = is_endo ? tEndoRowLoc : tEpiRowLoc;
	__global int* d_tColLoc = is_endo ? tEndoColLoc : tEpiColLoc;
	__global fp* d_T = is_endo ? d_endoT : d_epiT;

	int in2_elem = common->in2_elem;
	int in_mod_elem = common->in_mod_elem;
	int conv_elem = common->conv_elem;
	int in2_pad_elem = common->in2_pad_elem;
	int in2_sub_elem = common->in2_sub_elem;
	int in2_sub2_sqr_elem = common->in2_sub2_sqr_elem;
	int tMask_elem = common->tMask_elem;
	int mask_conv_elem = common->mask_conv_elem;

	int offset_in2 = point_no * in2_elem;
	int offset_in_mod = point_no * in_mod_elem;
	int offset_conv = point_no * conv_elem;
	int offset_in2_pad = point_no * in2_pad_elem;
	int offset_in2_sub = point_no * in2_sub_elem;
	int offset_in2_sub2_sqr = point_no * in2_sub2_sqr_elem;
	int offset_tMask = point_no * tMask_elem;
	int offset_mask_conv = point_no * mask_conv_elem;

	__global fp* p_in2 = d_in2 + offset_in2;
	__global fp* p_in2_sqr = d_in2_sqr + offset_in2;
	__global fp* p_in_mod = d_in_mod + offset_in_mod;
	__global fp* p_in_sqr = d_in_sqr + offset_in_mod;
	__global fp* p_conv = d_conv + offset_conv;
	__global fp* p_in2_pad = d_in2_pad + offset_in2_pad;
	__global fp* p_in2_sub = d_in2_sub + offset_in2_sub;
	__global fp* p_in2_sub2_sqr = d_in2_sub2_sqr + offset_in2_sub2_sqr;
	__global fp* p_tMask = d_tMask + offset_tMask;
	__global fp* p_mask_conv = d_mask_conv + offset_mask_conv;

	fp* d_in;
	int ei_new, rot_row, rot_col, in2_rowlow, in2_collow, jp1, ja1, ja2, ip1, ia1, ia2, ja, jb, ia, ib;
	fp s;
	int i, j, row, col, ori_row, ori_col, position, pos_ori, cent, tMask_row, tMask_col;
	fp sum, temp, temp2, in_final_sum, in_sqr_final_sum, mean, mean_sqr, variance, deviation, denomT;
	int pointer, ori_pointer, loc_pointer, fin_max_coo, largest_row, largest_col, offset_row, offset_col;
	fp fin_max_val;

	int in_pointer = point_no * in_mod_elem;

	if(frame_no == 0){
		pointer = point_no * common->no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no];
		d_tColLoc[pointer] = d_Col[point_no];

		d_in = d_T + in_pointer;

		for(col=0; col<common->in_mod_cols; col++){
			for(row=0; row<common->in_mod_rows; row++){
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				if(ori_row >= 0 && ori_row < common->frame_rows && ori_col >= 0 && ori_col < common->frame_cols) {
					ori_pointer = ori_col * common->frame_rows + ori_row;
					d_in[col * common->in_mod_rows + row] = d_frame[ori_pointer];
				}
			}
		}
	}

	if(frame_no != 0){
		in2_rowlow = d_Row[point_no] - common->sSize;
		in2_collow = d_Col[point_no] - common->sSize;

		for(col=0; col<common->in2_cols; col++){
			for(row=0; row<common->in2_rows; row++){
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				if(ori_row >= 0 && ori_row < common->frame_rows && ori_col >= 0 && ori_col < common->frame_cols) {
					temp = d_frame[ori_col * common->frame_rows + ori_row];
					p_in2[col * common->in2_rows + row] = temp;
					p_in2_sqr[col * common->in2_rows + row] = temp * temp;
				}
			}
		}

		d_in = d_T + in_pointer;

		for(col=0; col<common->in_mod_cols; col++){
			for(row=0; row<common->in_mod_rows; row++){
				rot_row = (common->in_mod_rows - 1) - row;
				rot_col = (common->in_mod_rows - 1) - col;
				pointer = rot_col * common->in_mod_rows + rot_row;
				temp = d_in[pointer];
				p_in_mod[col * common->in_mod_rows + row] = temp;
				p_in_sqr[pointer] = temp * temp;
			}
		}

		in_final_sum = 0;
		for(i=0; i<in_mod_elem; i++){
			in_final_sum += d_in[i];
		}

		in_sqr_final_sum = 0;
		for(i=0; i<in_mod_elem; i++){
			in_sqr_final_sum += p_in_sqr[i];
		}

		mean = in_final_sum / in_mod_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / in_mod_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(in_mod_elem - 1)) * deviation;

		for(col=1; col<=common->conv_cols; col++){
			j = col + common->joffset;
			jp1 = j + 1;
			if(common->in2_cols < jp1) ja1 = jp1 - common->in2_cols; else ja1 = 1;
			if(common->in_mod_cols < j) ja2 = common->in_mod_cols; else ja2 = j;

			for(row=1; row<=common->conv_rows; row++){
				i = row + common->ioffset;
				ip1 = i + 1;
				if(common->in2_rows < ip1) ia1 = ip1 - common->in2_rows; else ia1 = 1;
				if(common->in_mod_rows < i) ia2 = common->in_mod_rows; else ia2 = i;

				s = 0;
				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s += p_in_mod[common->in_mod_rows * (ja-1) + ia-1] * p_in2[common->in2_rows * (jb-1) + ib-1];
					}
				}
				p_conv[(col-1) * common->conv_rows + (row-1)] = s;
			}
		}

		for(col=0; col<common->in2_pad_cols; col++){
			for(row=0; row<common->in2_pad_rows; row++){
				if(row > (common->in2_pad_add_rows-1) && row < (common->in2_pad_add_rows+common->in2_rows) &&
				   col > (common->in2_pad_add_cols-1) && col < (common->in2_pad_add_cols+common->in2_cols)){
					ori_row = row - common->in2_pad_add_rows;
					ori_col = col - common->in2_pad_add_cols;
					p_in2_pad[col * common->in2_pad_rows + row] = p_in2[ori_col * common->in2_rows + ori_row];
				} else {
					p_in2_pad[col * common->in2_pad_rows + row] = 0;
				}
			}
		}

		for(ei_new=0; ei_new<common->in2_pad_cols; ei_new++){
			pos_ori = ei_new * common->in2_pad_rows;
			sum = 0;
			for(position=pos_ori; position<pos_ori+common->in2_pad_rows; position++){
				p_in2_pad[position] += sum;
				sum = p_in2_pad[position];
			}
		}

		for(col=0; col<common->in2_sub_cols; col++){
			for(row=0; row<common->in2_sub_rows; row++){
				ori_row = row + common->in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common->in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad[ori_col * common->in2_pad_rows + ori_row];
				ori_row = row + common->in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common->in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad[ori_col * common->in2_pad_rows + ori_row];
				p_in2_sub[col * common->in2_sub_rows + row] = temp - temp2;
			}
		}

		for(ei_new=0; ei_new<common->in2_sub_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0;
			for(position=pos_ori; position<pos_ori+common->in2_sub_elem; position+=common->in2_sub_rows){
				p_in2_sub[position] += sum;
				sum = p_in2_sub[position];
			}
		}

		for(col=0; col<common->in2_sub2_sqr_cols; col++){
			for(row=0; row<common->in2_sub2_sqr_rows; row++){
				ori_row = row + common->in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common->in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub[ori_col * common->in2_sub_rows + ori_row];
				ori_row = row + common->in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common->in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub[ori_col * common->in2_sub_rows + ori_row];
				temp2 = temp - temp2;
				p_in2_sub2_sqr[col * common->in2_sub2_sqr_rows + row] = temp2 * temp2;
				p_conv[col * common->in2_sub2_sqr_rows + row] -= temp2 * in_final_sum / in_mod_elem;
			}
		}

		for(col=0; col<common->in2_pad_cols; col++){
			for(row=0; row<common->in2_pad_rows; row++){
				if(row > (common->in2_pad_add_rows-1) && row < (common->in2_pad_add_rows+common->in2_rows) &&
				   col > (common->in2_pad_add_cols-1) && col < (common->in2_pad_add_cols+common->in2_cols)){
					ori_row = row - common->in2_pad_add_rows;
					ori_col = col - common->in2_pad_add_cols;
					p_in2_pad[col * common->in2_pad_rows + row] = p_in2_sqr[ori_col * common->in2_rows + ori_row];
				} else {
					p_in2_pad[col * common->in2_pad_rows + row] = 0;
				}
			}
		}

		for(ei_new=0; ei_new<common->in2_pad_cols; ei_new++){
			pos_ori = ei_new * common->in2_pad_rows;
			sum = 0;
			for(position=pos_ori; position<pos_ori+common->in2_pad_rows; position++){
				p_in2_pad[position] += sum;
				sum = p_in2_pad[position];
			}
		}

		for(col=0; col<common->in2_sub_cols; col++){
			for(row=0; row<common->in2_sub_rows; row++){
				ori_row = row + common->in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common->in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad[ori_col * common->in2_pad_rows + ori_row];
				ori_row = row + common->in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common->in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad[ori_col * common->in2_pad_rows + ori_row];
				p_in2_sub[col * common->in2_sub_rows + row] = temp - temp2;
			}
		}

		for(ei_new=0; ei_new<common->in2_sub_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0;
			for(position=pos_ori; position<pos_ori+common->in2_sub_elem; position+=common->in2_sub_rows){
				p_in2_sub[position] += sum;
				sum = p_in2_sub[position];
			}
		}

		for(col=0; col<common->conv_cols; col++){
			for(row=0; row<common->conv_rows; row++){
				ori_row = row + common->in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common->in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub[ori_col * common->in2_sub_rows + ori_row];
				ori_row = row + common->in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common->in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub[ori_col * common->in2_sub_rows + ori_row];
				temp2 = temp - temp2;
				temp2 = temp2 - (p_in2_sub2_sqr[col * common->conv_rows + row] / in_mod_elem);
				if(temp2 < 0) temp2 = 0;
				temp2 = sqrt(temp2);
				temp2 = denomT * temp2;
				p_conv[col * common->conv_rows + row] /= temp2;
			}
		}

		cent = common->sSize + common->tSize + 1;
		pointer = frame_no - 1 + point_no * common->no_frames;
		if(pointer >= 0) {
			tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
			tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

			for(ei_new=0; ei_new<tMask_elem; ei_new++){
				p_tMask[ei_new] = 0;
			}
			if(tMask_row >= 0 && tMask_row < common->tMask_rows && tMask_col >= 0 && tMask_col < common->tMask_cols)
				p_tMask[tMask_col * common->tMask_rows + tMask_row] = 1;

			for(col=1; col<=common->mask_conv_cols; col++){
				j = col + common->mask_conv_joffset;
				jp1 = j + 1;
				if(common->mask_cols < jp1) ja1 = jp1 - common->mask_cols; else ja1 = 1;
				if(common->tMask_cols < j) ja2 = common->tMask_cols; else ja2 = j;

				for(row=1; row<=common->mask_conv_rows; row++){
					i = row + common->mask_conv_ioffset;
					ip1 = i + 1;
					if(common->mask_rows < ip1) ia1 = ip1 - common->mask_rows; else ia1 = 1;
					if(common->tMask_rows < i) ia2 = common->tMask_rows; else ia2 = i;

					s = 0;
					for(ja=ja1; ja<=ja2; ja++){
						jb = jp1 - ja;
						for(ia=ia1; ia<=ia2; ia++){
							ib = ip1 - ia;
							if(ja-1 >= 0 && ja-1 < common->tMask_cols && ia-1 >= 0 && ia-1 < common->tMask_rows)
								s += p_tMask[common->tMask_rows * (ja-1) + ia-1] * 1;
						}
					}
					int idx = (col-1) * common->conv_rows + (row-1);
					if(idx >= 0 && idx < mask_conv_elem)
						p_mask_conv[idx] = p_conv[idx] * s;
				}
			}

			fin_max_val = 0;
			fin_max_coo = 0;
			for(i=0; i<mask_conv_elem; i++){
				if(p_mask_conv[i] > fin_max_val){
					fin_max_val = p_mask_conv[i];
					fin_max_coo = i;
				}
			}

			largest_row = (fin_max_coo + 1) % common->mask_conv_rows - 1;
			largest_col = (fin_max_coo + 1) / common->mask_conv_rows;
			if((fin_max_coo + 1) % common->mask_conv_rows == 0){
				largest_row = common->mask_conv_rows - 1;
				largest_col--;
			}
			largest_row++;
			largest_col++;
			offset_row = largest_row - common->in_mod_rows - (common->sSize - common->tSize);
			offset_col = largest_col - common->in_mod_cols - (common->sSize - common->tSize);
			pointer = point_no * common->no_frames + frame_no;
			d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
			d_tColLoc[pointer] = d_Col[point_no] + offset_col;
		}
	}

	if(frame_no != 0 && (frame_no % 10 == 0)){
		loc_pointer = point_no * common->no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		d_in = d_T + in_pointer;
		for(col=0; col<common->in_mod_cols; col++){
			for(row=0; row<common->in_mod_rows; row++){
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				if(ori_row >= 0 && ori_row < common->frame_rows && ori_col >= 0 && ori_col < common->frame_cols) {
					ori_pointer = ori_col * common->frame_rows + ori_row;
					d_in[col * common->in_mod_rows + row] = common->alpha * d_in[col * common->in_mod_rows + row] + (1.00 - common->alpha) * d_frame[ori_pointer];
				}
			}
		}
	}
}
